sql:
SELECT AVG(s.waist) AS average_waist_size
FROM sizes s
INNER JOIN product_sizes ps ON s.size_id = ps.size_id;

SELECT products.product_name, brands.brand_name
FROM products
INNER JOIN brands ON products.brand_id = brands.brand_id;

external_knowledge:
- "garden of commerce" is used metaphorically to refer to the market;
- "blossoms and withers with the seasons" indicates the fluctuation of supply and demand;
- "shadows cast by the wind of consumer demand" represents the quantity of products demanded by consumers, here metaphorically linked to sales;
- "first thaw and the budding of spring in 2022" refers to the period from January 1, 2022, to March 31, 2022, used to indicate the time frame for the query.

sql:
SELECT size_id, size, waist
FROM sizes
WHERE waist < (SELECT AVG(waist) FROM sizes)
  AND size_id IN (
      SELECT size_id FROM (
          SELECT size_id, NTILE(4) OVER (ORDER BY waist) AS quartile
          FROM sizes
      ) WHERE quartile = 1
  )
ORDER BY waist DESC;

SELECT size_id, change_date, previous_size, new_size
FROM size_history
WHERE size_id = 1 AND previous_size != new_size;

SELECT size_type_name 
FROM size_types 
WHERE size_type_id = 1;

external_knowledge:
- 'Sold items' refer to products that have been involved in sales ('sale' in the change type).;
- 'Currently available' indicates that the stock quantity is greater than zero. ;
- 'Average turnover rate' is an aggregated measure of how quickly the stock of a particular size is being sold. ;
